// محاسبات پیشرفته KPI و تجمیع داده‌ها
const dbData = $node['PostgreSQL: Incremental Extract'].json;
const stripeData = $node['HTTP Request: Stripe'].json.data || [];

// شبیه‌سازی محاسبات (در واقعیت از داده‌های واقعی استفاده می‌شود)
const newUsers = parseInt(dbData.new_users) || 0;
const dbRevenue = parseFloat(dbData.total_revenue) || 0;
const stripeRevenue = stripeData.reduce((sum, event) => sum + (event.data.object.amount_paid / 100), 0);
const totalRevenue = dbRevenue + stripeRevenue;

// محاسبات KPI (فرمول‌های ساده‌شده برای نمونه)
const cac = newUsers > 0 ? 5000 / newUsers : 0; // فرض هزینه بازاریابی 5000
const ltv = totalRevenue / (newUsers || 1) * 12; // پیش‌بینی سالانه
const churnRate = 2.5; // درصد فرضی
const mrr = totalRevenue; 

// تشخیص ناهنجاری (Anomaly Detection)
const churnWarning = churnRate > 5.0 ? '⚠️ هشدار: نرخ ریزش بالاتر از حد مجاز (5%) است!' : '✅ نرمال';

return [{
  json: {
    report_date: new Date().toISOString().split('T')[0],
    new_users: newUsers,
    total_revenue: totalRevenue.toFixed(2),
    mrr: mrr.toFixed(2),
    cac: cac.toFixed(2),
    ltv: ltv.toFixed(2),
    churn_rate: churnRate,
    churn_warning: churnWarning,
    new_watermark: new Date().toISOString()
  }
}];

// تولید گزارش HTML پویا و زیبا
const data = $input.first().json;
const churnColor = data.churn_rate > 5.0 ? '#dc3545' : '#28a745';

const html = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; color: #333; }
    .header { background: #007bff; color: white; padding: 20px; text-align: center; }
    .kpi-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; padding: 20px; }
    .kpi-card { background: #f8f9fa; padding: 20px; border-radius: 8px; text-align: center; border: 1px solid #dee2e6; }
    .kpi-value { font-size: 24px; font-weight: bold; color: #007bff; }
    .kpi-label { font-size: 14px; color: #6c757d; margin-top: 5px; }
    .alert { background: #fff3cd; color: #856404; padding: 15px; margin: 20px; border-radius: 5px; border-left: 4px solid #ffc107; }
  </style>
</head>
<body>
  <div class="header"><h1>Weekly BI Executive Report</h1><p>Date: ${data.report_date}</p></div>
  <div class="kpi-grid">
    <div class="kpi-card"><div class="kpi-value">$${data.mrr}</div><div class="kpi-label">Monthly Recurring Revenue (MRR)</div></div>
    <div class="kpi-card"><div class="kpi-value">${data.new_users}</div><div class="kpi-label">New Users Acquired</div></div>
    <div class="kpi-card"><div class="kpi-value">$${data.cac}</div><div class="kpi-label">Customer Acquisition Cost (CAC)</div></div>
    <div class="kpi-card"><div class="kpi-value">$${data.ltv}</div><div class="kpi-label">Lifetime Value (LTV)</div></div>
    <div class="kpi-card"><div class="kpi-value" style="color: ${churnColor}">${data.churn_rate}%</div><div class="kpi-label">Churn Rate</div></div>
    <div class="kpi-card"><div class="kpi-value">$${data.total_revenue}</div><div class="kpi-label">Total Period Revenue</div></div>
  </div>
  ${data.churn_rate > 5.0 ? `<div class="alert">${data.churn_warning}</div>` : ''}
  <p style="text-align: center; color: #6c757d; font-size: 12px;">Generated automatically by n8n BI Pipeline</p>
</body>
</html>`;

return [{ json: { html_report: html, ...data } }];

